164→void ULFPWorldMapEditorComponent::HandleEdgeConnection(ALFPWorldMapNode* Node)
165→{
166→	if (!Node) return;
167→
168→	ALFPWorldMapManager* Manager = GetWorldMapManager();
169→	if (!Manager) return;
170→
171→	if (!EdgeStartNode)
172→	{
173→		// 第一次点击：记录起点
174→		EdgeStartNode = Node;
175→		EdgeStartNode->SetHighlighted(true);
176→		UE_LOG(LogTemp, Log, TEXT("选择边起点: 节点 %d"), EdgeStartNode->NodeID);
177→	}
178→	else
179→	{
180→		// 第二次点击：创建边
181→		if (EdgeStartNode != Node)
182→		{
183→			Manager->AddEdge(EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
184→			UE_LOG(LogTemp, Log, TEXT("创建边: %d -> %d (消耗 %d 回合)"),
185→				EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
186→		}
187→
188→		// 清除高亮和状态
189→		EdgeStartNode->SetHighlighted(false);
190→		EdgeStartNode = nullptr;
191→	}
192→}
193→
194→void ULFPWorldMapEditorComponent::HandleEdgeRemoval(ALFPWorldMapNode* Node)
195→{
196→	if (!Node) return;
197→
198→	ALFPWorldMapManager* Manager = GetWorldMapManager();
199→	if (!Manager) return;
200→
201→	if (!EdgeRemovalStartNode)
202→	{
203→		// 第一次点击：记录起点
204→		EdgeRemovalStartNode = Node;
205→		EdgeRemovalStartNode->SetHighlighted(true);
206→		UE_LOG(LogTemp, Log, TEXT("选择要删除的边起点: 节点 %d"), EdgeRemovalStartNode->NodeID);
207→	}
208→	else
209→	{
210→		// 第二次点击：删除边
211→		if (EdgeRemovalStartNode != Node)
212→		{
213→			bool bRemoved = Manager->RemoveEdge(EdgeRemovalStartNode->NodeID, Node->NodeID);
214→			if (bRemoved)
215→			{
216→				UE_LOG(LogTemp, Log, TEXT("删除边: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
217→			}
218→			else
219→			{
220→				UE_LOG(LogTemp, Warning, TEXT("边不存在: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
221→			}
222→		}
223→
224→		// 清除高亮和状态
225→		EdgeRemovalStartNode->SetHighlighted(false);
226→		EdgeRemovalStartNode = nullptr;
227→	}
228→}
