230→void ULFPWorldMapEditorComponent::MoveSelectedNodeTo(FVector2D NewPos)
231→{
232→	if (!SelectedNode) return;
233→
234→	SelectedNode->SetPosition2D(NewPos);
235→
236→	// 更新所有关联边的视觉位置
237→	ALFPWorldMapManager* Manager = GetWorldMapManager();
238→	if (!Manager) return;
239→
240→	TArray<ALFPWorldMapNode*> Neighbors = Manager->GetNeighbors(SelectedNode->NodeID);
241→	for (ALFPWorldMapNode* Neighbor : Neighbors)
242→	{
243→		if (ALFPWorldMapEdge* Edge = Manager->GetEdge(SelectedNode->NodeID, Neighbor->NodeID))
244→		{
245→			Edge->UpdateVisualPosition(SelectedNode->GetActorLocation(), Neighbor->GetActorLocation());
246→		}
247→	}
248→
249→	UE_LOG(LogTemp, Log, TEXT("移动节点 %d 到 (%.1f, %.1f)"), SelectedNode->NodeID, NewPos.X, NewPos.Y);
250→}
