101→	UButton* Btn = GetUnitButton(Index);
102→
103→	bool bPlaced = PlacedStates.IsValidIndex(Index) && PlacedStates[Index];
104→
105→	// 已放置：禁用按钮，防止重复生成
106→	if (Btn)
107→	{
