544→// ============== 迷雾系统 ==============
545→
546→TSet<int32> ALFPWorldMapManager::GetNodesWithinGraphDistance(int32 StartNodeID, int32 MaxDistance) const
547→{
548→	TSet<int32> Result;
549→
550→	if (!AdjacencyList.Contains(StartNodeID)) return Result;
551→
552→	// BFS
553→	TQueue<TPair<int32, int32>> Queue; // <NodeID, Distance>
554→	TSet<int32> Visited;
555→
556→	Queue.Enqueue(TPair<int32, int32>(StartNodeID, 0));
557→	Visited.Add(StartNodeID);
558→
559→	while (!Queue.IsEmpty())
560→	{
561→		TPair<int32, int32> Current;
562→		Queue.Dequeue(Current);
563→
564→		int32 CurrentID = Current.Key;
565→		int32 CurrentDist = Current.Value;
566→
567→		Result.Add(CurrentID);
568→
569→		if (CurrentDist >= MaxDistance) continue;
570→
571→		if (const TSet<int32>* Neighbors = AdjacencyList.Find(CurrentID))
572→		{
573→			for (int32 NeighborID : *Neighbors)
574→			{
575→				if (!Visited.Contains(NeighborID))
576→				{
577→					Visited.Add(NeighborID);
578→					Queue.Enqueue(TPair<int32, int32>(NeighborID, CurrentDist + 1));
579→				}
580→			}
581→		}
582→	}
583→
584→	return Result;
585→}
