587→void ALFPWorldMapManager::UpdateFog()
588→{
589→	if (!PlayerState) return;
590→
591→	// 获取视野范围内的节点
592→	TSet<int32> VisibleNodes = GetNodesWithinGraphDistance(PlayerState->CurrentNodeID, FogVisionRange);
593→
594→	// 添加到永久揭露集合
595→	for (int32 NodeID : VisibleNodes)
596→	{
597→		PlayerState->RevealedNodeIDs.Add(NodeID);
598→	}
599→
600→	// 更新所有节点的视觉状态
601→	for (auto& Pair : NodeMap)
602→	{
603→		if (!Pair.Value) continue;
604→
605→		Pair.Value->bIsRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key);
606→		Pair.Value->UpdateVisualState();
607→	}
608→
609→	// 更新边的可见性（两端都揭露才可见）
610→	for (auto& Pair : EdgeMap)
611→	{
612→		if (!Pair.Value) continue;
613→
614→		bool bBothRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key.X)
615→			&& PlayerState->RevealedNodeIDs.Contains(Pair.Key.Y);
616→		Pair.Value->SetActorHiddenInGame(!bBothRevealed);
617→	}
618→}
